{
  "functions": [
    {
      "name": "智能代码补全与生成",
      "description": "基于上下文理解，提供实时代码补全、函数生成、代码片段建议。支持多种编程语言，能够根据注释或函数名自动生成完整代码逻辑，显著提升编码效率。"
    },
    {
      "name": "代码审查与Bug修复",
      "description": "自动检测代码中的潜在错误、安全漏洞和性能问题，并提供修复建议。支持对选中代码段进行实时审查，帮助开发者在提交前发现并解决问题。"
    },
    {
      "name": "单元测试自动生成",
      "description": "根据已有代码自动生成单元测试用例，支持主流测试框架。开发者只需选择目标函数或类，即可快速生成覆盖主要路径的测试代码，提升代码质量。"
    },
    {
      "name": "智能问答与文档查询",
      "description": "内置 AI 问答功能，开发者可以直接在 IDE 中提问，获取技术问题的解答、API 使用说明、最佳实践建议等。支持引用项目上下文，回答更精准。"
    }
  ],
  "roles": [
    {
      "name": "开发者",
      "description": "日常编码中，开发者可使用 CodeBuddy 进行代码补全、Bug 修复和测试生成，减少重复劳动，专注于业务逻辑。尤其适合全栈工程师和需要频繁切换语言的开发者。"
    },
    {
      "name": "科研人员",
      "description": "科研人员在进行算法实现、数据处理脚本编写时，可利用 CodeBuddy 快速生成代码框架和测试用例，减少调试时间。本地运行保障了研究数据的隐私安全。"
    },
    {
      "name": "数据分析师",
      "description": "数据分析师在编写 SQL、Python 数据处理脚本时，CodeBuddy 可提供语法提示、错误检查和优化建议，帮助快速完成数据清洗、分析和可视化代码的编写。"
    }
  ],
  "features": [
    {
      "name": "完全本地化运行",
      "description": "所有代码处理均在本地设备上完成，无需上传至云端，确保企业级代码安全和隐私合规。支持离线使用，不受网络环境影响。"
    },
    {
      "name": "多IDE深度集成",
      "description": "支持 VS Code、JetBrains 系列（IntelliJ IDEA、PyCharm、GoLand 等）主流 IDE，安装即用，不改变开发者原有工作流。"
    },
    {
      "name": "多模型支持与灵活切换",
      "description": "支持接入多种开源和商业大语言模型（如 CodeLlama、StarCoder 等），用户可根据任务需求和硬件配置自由切换模型，平衡性能与效果。"
    }
  ],
  "scenarios": [
    {
      "name": "企业级代码安全开发",
      "description": "某金融科技公司要求所有代码不得上传至外部服务器。开发团队部署 CodeBuddy 本地版，所有代码补全和审查均在内部服务器完成，既提升了开发效率，又满足了合规要求。"
    },
    {
      "name": "快速修复线上Bug",
      "description": "开发者在排查线上问题时，选中报错代码段，使用 CodeBuddy 的“Bug 修复”功能，AI 自动分析错误原因并给出修复建议，开发者确认后一键应用，将修复时间从小时级缩短到分钟级。"
    },
    {
      "name": "新项目代码规范落地",
      "description": "团队启动新项目时，使用 CodeBuddy 的代码审查功能，自动检查代码是否符合团队规范（命名、注释、结构等），并给出修改建议，帮助新成员快速适应代码风格。"
    }
  ],
  "pricing_plan": [
    {
      "name": "免费版（Community）",
      "description": "免费使用，支持基础代码补全和问答功能，每日有调用次数限制（约200次/天），支持 VS Code 和 JetBrains 基础集成，适合个人开发者体验和轻量使用。"
    },
    {
      "name": "专业版（Pro）",
      "description": "按年订阅，约 ￥299/年。解除每日调用限制，支持高级代码审查、单元测试生成、多模型切换，优先获得新功能更新，适合全职开发者。"
    },
    {
      "name": "企业版（Enterprise）",
      "description": "按需定价，支持私有化部署、团队管理后台、SSO 集成、审计日志、专属模型微调。适合对数据安全和团队协作有高要求的企业客户。"
    }
  ],
  "usage": [
    {
      "name": "在 VS Code 中使用",
      "description": "1. 打开 VS Code，进入扩展市场搜索“CodeBuddy”并安装。2. 安装完成后，点击左侧 CodeBuddy 图标打开面板。3. 首次使用需登录或注册账号，选择本地模型或云端模型。4. 在编辑器中编写代码时，CodeBuddy 会自动提供补全建议；选中代码右键可选择“审查代码”或“生成测试”。"
    },
    {
      "name": "在 JetBrains IDE 中使用",
      "description": "1. 打开 IntelliJ IDEA / PyCharm 等 IDE，进入 Settings > Plugins，搜索“CodeBuddy”并安装。2. 重启 IDE 后，在右侧工具栏找到 CodeBuddy 标签。3. 配置模型路径（本地模型需提前下载）或登录云端服务。4. 在代码编辑区使用快捷键（默认 Alt+C）唤起 AI 助手，输入问题或选择功能。"
    }
  ],
  "questions": [
    {
      "name": "CodeBuddy 是否完全免费？",
      "description": "CodeBuddy 提供免费社区版，支持基础功能但有每日调用次数限制（约200次/天）。如果需要无限制使用和高级功能（如代码审查、测试生成），建议升级到专业版（￥299/年）。企业用户可联系销售获取私有化部署方案。"
    },
    {
      "name": "CodeBuddy 的代码数据会上传到云端吗？",
      "description": "CodeBuddy 支持完全本地化运行，用户可以选择使用本地模型，所有代码处理均在本地设备完成，不会上传到任何云端服务器。如果使用云端模型（如默认的远程 API），则代码会经过加密传输，但建议对代码安全有严格要求的用户选择本地模式。"
    },
    {
      "name": "CodeBuddy 支持哪些编程语言？",
      "description": "CodeBuddy 支持主流编程语言，包括但不限于 Python、JavaScript、TypeScript、Java、Go、C/C++、Rust、Ruby、PHP、SQL 等。具体语言支持程度取决于所选的底层模型，建议使用 CodeLlama 或 StarCoder 等专门针对代码优化的模型以获得最佳效果。"
    }
  ]
}

{
  "functions": [
    {
      "name": "可视化Bot构建",
      "description": "提供直观的拖拽式界面和自然语言配置方式，用户无需编写代码即可定义Bot的人设、技能和知识库。通过简单的配置，就能创建一个具备特定功能的AI助手，如客服、写作助手或学习伴侣。"
    },
    {
      "name": "丰富的插件与工具集",
      "description": "内置了搜索、图像生成（如DALL-E）、数据分析、代码解释器、网页解析等多种插件。Bot可以调用这些插件来执行复杂任务，例如实时联网搜索信息、生成图片、处理Excel文件等，极大地扩展了Bot的能力边界。"
    },
    {
      "name": "知识库管理",
      "description": "支持用户上传文本、PDF、网页链接等多种格式的文档，构建专属知识库。Bot在回答问题时可以基于这些私有知识进行检索和生成，确保回答的准确性和专业性，适用于企业知识问答、产品说明书等场景。"
    },
    {
      "name": "工作流自动化",
      "description": "提供工作流（Workflow）功能，允许用户将多个插件、模型和逻辑判断节点串联起来，设计复杂的自动化任务流程。例如，可以创建一个工作流，自动从邮件中提取信息、查询数据库并生成报告，实现端到端的任务自动化。"
    }
  ],
  "roles": [
    {
      "name": "开发者",
      "description": "开发者可以利用Coze快速搭建AI应用原型，测试不同模型和插件组合的效果。通过API接口，可以将Coze上创建的Bot集成到自己的网站、App或企业内部系统中，大幅降低AI功能的开发成本和周期。"
    },
    {
      "name": "内容创作者",
      "description": "内容创作者可以创建专属的写作助手、文案生成Bot或图像生成Bot。通过配置知识库（如自己的文章合集），Bot能生成风格一致的内容。创作者还可以利用工作流自动化内容发布流程，提升创作效率。"
    },
    {
      "name": "营销人",
      "description": "营销人员可以快速构建智能客服Bot，用于网站或社交媒体上的用户咨询。通过配置产品知识库和营销话术，Bot能够7x24小时解答客户问题、收集潜在客户信息，并自动生成营销文案或活动方案，提升营销转化率。"
    }
  ],
  "features": [
    {
      "name": "多模型集成",
      "description": "平台集成了包括字节跳动自研的豆包模型、阿里通义千问、智谱GLM等多种主流大语言模型。用户可以根据任务需求（如成本、速度、推理能力）灵活切换或组合使用不同模型，实现最优效果。"
    },
    {
      "name": "一键多渠道发布",
      "description": "创建的Bot可以一键发布到多个主流平台，包括飞书、微信公众号、企业微信、网页版以及独立的API接口。这种跨平台能力使得Bot能够无缝融入用户现有的工作流和社交生态中。"
    },
    {
      "name": "零代码与低代码结合",
      "description": "既支持完全零代码的拖拽式配置，也提供了代码节点和API接口，满足高级开发者的定制化需求。这种灵活性使得非技术人员和资深开发者都能在同一平台上高效协作。"
    }
  ],
  "scenarios": [
    {
      "name": "企业智能客服",
      "description": "企业可以将产品手册、常见问题FAQ等文档上传至Coze知识库，创建一个智能客服Bot。将该Bot发布到企业官网或微信公众号后，用户提问时，Bot会自动从知识库中检索答案并回复，大幅降低人工客服成本，提升响应速度。"
    },
    {
      "name": "个人学习助手",
      "description": "学生或自学者可以创建一个学习助手Bot。将教材、笔记或论文上传为知识库，并配置搜索插件。当遇到难题时，可以向Bot提问，它不仅能基于知识库给出解释，还能联网搜索最新资料，帮助用户高效学习。"
    },
    {
      "name": "自动化内容生成与分发",
      "description": "营销人员可以创建一个工作流：首先让Bot根据热点话题生成一篇公众号文章，然后调用图像生成插件配图，最后通过API自动发布到公众号后台。整个过程无需人工干预，实现了从创意到发布的全流程自动化。"
    }
  ],
  "pricing_plan": [
    {
      "name": "免费版",
      "description": "提供基础的Bot创建、调试和发布功能。用户可以使用平台内置的插件和模型（有调用次数限制），创建最多50个Bot，并支持发布到网页和飞书等渠道。适合个人用户和小规模测试。"
    },
    {
      "name": "专业版（Pro）",
      "description": "在免费版基础上，提供更高的模型调用额度、更多的插件使用次数和更大的知识库存储空间。支持创建更多数量的Bot，并提供优先的技术支持。适合有较高使用需求的内容创作者和开发者。"
    },
    {
      "name": "企业版",
      "description": "提供定制化的解决方案，包括私有化部署、专属模型微调、高级安全审计、SLA保障以及专属客户成功经理。适合对数据安全、性能和合规性有严格要求的大型企业。具体价格需联系销售。"
    }
  ],
  "usage": [
    {
      "name": "网页端创建Bot",
      "description": "1. 访问Coze官网并登录/注册账号。2. 点击「创建Bot」按钮。3. 在「人设与回复逻辑」框中用自然语言描述Bot的角色和任务（例如：“你是一个专业的健身教练，回答关于增肌和减脂的问题”）。4. 在「技能」部分，为Bot添加需要的插件（如搜索、图像生成）和知识库。5. 在右侧预览窗口进行对话测试。6. 测试满意后，点击「发布」，选择发布到网页、飞书或API等渠道。"
    },
    {
      "name": "通过API集成",
      "description": "1. 在Coze平台上创建并发布一个Bot。2. 进入Bot的「发布」页面，获取API Token和Bot ID。3. 在你的应用程序（如Python、JavaScript项目）中，使用Coze提供的SDK或直接调用HTTP API。4. 构造请求，将用户输入的消息发送给Bot API。5. 接收并处理Bot返回的回复，将其展示给最终用户。这种方式适合将Coze Bot深度集成到自有产品中。"
    }
  ],
  "questions": [
    {
      "name": "Coze是免费的吗？",
      "description": "Coze提供免费版，用户无需付费即可创建和发布Bot，体验核心功能。免费版包含一定的模型调用次数和插件使用额度，足以满足个人和小型项目的需求。对于更高阶的需求，Coze也提供了专业版和企业版付费方案。"
    },
    {
      "name": "不会编程可以用Coze吗？",
      "description": "完全可以。Coze的核心设计理念就是降低AI应用开发门槛。用户通过自然语言描述和可视化拖拽即可完成Bot的创建、配置和发布，整个过程无需编写任何代码。平台内置的插件和工作流功能也都是通过图形化界面操作的。"
    },
    {
      "name": "Coze创建的Bot可以发布到微信吗？",
      "description": "可以。Coze支持将创建的Bot一键发布到微信公众号（需进行配置）。此外，还支持发布到飞书、企业微信、网页版以及通过API集成到任何第三方应用中，实现了多渠道的灵活部署。"
    }
  ]
}

